  1→package auth
  2→
  3→import (
  4→	"context"
  5→	"testing"
  6→	"time"
  7→
  8→	"github.com/golang-jwt/jwt/v5"
  9→	"github.com/google/uuid"
 10→)
 11→
 12→const testSecret = "test-secret-key-for-hmac-validation"
 13→
 14→func makeHMACToken(t *testing.T, secret string, claims Claims) string {
 15→	t.Helper()
 16→	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
 17→	signed, err := token.SignedString([]byte(secret))
 18→	if err != nil {
 19→		t.Fatalf("failed to sign token: %v", err)
 20→	}
 21→	return signed
 22→}
 23→
 24→func TestHMACValidator_ValidToken(t *testing.T) {
 25→	uid := uuid.New()
 26→	tokenStr := makeHMACToken(t, testSecret, Claims{
 27→		RegisteredClaims: jwt.RegisteredClaims{
 28→			Subject:   uid.String(),
 29→			ExpiresAt: jwt.NewNumericDate(time.Now().Add(time.Hour)),
 30→		},
 31→		UserID:     uid,
 32→		Email:      "test@example.com",
 33→		ClientType: "web",
 34→	})
 35→
 36→	v := NewHMACValidator(testSecret)
 37→	claims, err := v.Validate(tokenStr)
 38→	if err != nil {
 39→		t.Fatalf("unexpected error: %v", err)
 40→	}
 41→	if claims.UserID != uid {
 42→		t.Errorf("UserID = %v, want %v", claims.UserID, uid)
 43→	}
 44→	if claims.Email != "test@example.com" {
 45→		t.Errorf("Email = %q, want %q", claims.Email, "test@example.com")
 46→	}
 47→	if claims.ClientType != "web" {
 48→		t.Errorf("ClientType = %q, want %q", claims.ClientType, "web")
 49→	}
 50→}
 51→
 52→func TestHMACValidator_ExpiredToken(t *testing.T) {
 53→	tokenStr := makeHMACToken(t, testSecret, Claims{
 54→		RegisteredClaims: jwt.RegisteredClaims{
 55→			ExpiresAt: jwt.NewNumericDate(time.Now().Add(-time.Hour)),
 56→		},
 57→	})
 58→
 59→	v := NewHMACValidator(testSecret)
 60→	_, err := v.Validate(tokenStr)
 61→	if err == nil {
 62→		t.Fatal("expected error for expired token")
 63→	}
 64→}
 65→
 66→func TestHMACValidator_WrongSecret(t *testing.T) {
 67→	tokenStr := makeHMACToken(t, testSecret, Claims{
 68→		RegisteredClaims: jwt.RegisteredClaims{
 69→			ExpiresAt: jwt.NewNumericDate(time.Now().Add(time.Hour)),
 70→		},
 71→	})
 72→
 73→	v := NewHMACValidator("wrong-secret")
 74→	_, err := v.Validate(tokenStr)
 75→	if err == nil {
 76→		t.Fatal("expected error for wrong secret")
 77→	}
 78→}
 79→
 80→func TestHMACValidator_MalformedToken(t *testing.T) {
 81→	v := NewHMACValidator(testSecret)
 82→	_, err := v.Validate("not-a-jwt")
 83→	if err == nil {
 84→		t.Fatal("expected error for malformed token")
 85→	}
 86→}
 87→
 88→func TestHMACValidator_RSASignedToken(t *testing.T) {
 89→	// An HS256 validator should reject tokens signed with a different method.
 90→	// We simulate this by creating a token that claims RS256 but is actually nonsense.
 91→	token := jwt.NewWithClaims(jwt.SigningMethodHS256, &Claims{
 92→		RegisteredClaims: jwt.RegisteredClaims{
 93→			ExpiresAt: jwt.NewNumericDate(time.Now().Add(time.Hour)),
 94→		},
 95→	})
 96→	// Override the header to claim RS256
 97→	token.Header["alg"] = "RS256"
 98→	// Sign with HMAC secret (the header lies about the algorithm)
 99→	signed, err := token.SignedString([]byte(testSecret))
100→	if err != nil {
101→		t.Fatalf("failed to sign token: %v", err)
102→	}
103→
104→	v := NewHMACValidator(testSecret)
105→	_, err = v.Validate(signed)
106→	if err == nil {
107→		t.Fatal("expected error for RS256-header token validated by HMAC validator")
108→	}
109→}
110→
111→func TestWithAndGetClaims(t *testing.T) {
112→	claims := &Claims{Email: "user@example.com"}
113→	ctx := WithClaims(context.Background(), claims)
114→
115→	got := GetClaims(ctx)
116→	if got == nil {
117→		t.Fatal("GetClaims returned nil")
118→	}
119→	if got.Email != "user@example.com" {
120→		t.Errorf("Email = %q, want %q", got.Email, "user@example.com")
121→	}
122→}
123→
124→func TestGetClaims_NoClaims(t *testing.T) {
125→	got := GetClaims(context.Background())
126→	if got != nil {
127→		t.Errorf("GetClaims on empty context = %v, want nil", got)
128→	}
129→}
