136→// CaptureBookmark creates a new bookmark item.
137→func (s *Service) CaptureBookmark(ctx context.Context, ownerID uuid.UUID, input BookmarkInput) (*Item, error) {
138→	if input.URL == "" {
139→		return nil, fmt.Errorf("item: capture bookmark: url is required")
140→	}
141→	if input.Source == "" {
142→		input.Source = "api"
143→	}
144→	if input.Sensitivity == "" {
145→		input.Sensitivity = "normal"
146→	}
147→
148→	tags := input.Tags
149→	if tags == nil {
150→		tags = []string{}
151→	}
152→
153→	query := fmt.Sprintf(`INSERT INTO items (owner_id, type, status, sensitivity, title, content_url, tags, source, metadata, auto_metadata)
154→		VALUES ($1, 'bookmark', 'pending', $2, $3, $4, $5, $6, '{}', '{}')
155→		RETURNING %s`, itemColumns)
156→
157→	row := s.pool.QueryRow(ctx, query,
158→		ownerID, input.Sensitivity, input.Title, input.URL, tags, input.Source)
159→
160→	it, err := scanItem(row)
161→	if err != nil {
162→		return nil, fmt.Errorf("item: capture bookmark: %w", err)
163→	}
164→	return it, nil
165→}
166→
167→// CaptureNote creates a new text note item.
168→func (s *Service) CaptureNote(ctx context.Context, ownerID uuid.UUID, input NoteInput) (*Item, error) {
169→	if input.Content == "" {
170→		return nil, fmt.Errorf("item: capture note: content is required")
171→	}
172→	if input.Source == "" {
173→		input.Source = "api"
174→	}
175→	if input.Sensitivity == "" {
176→		input.Sensitivity = "normal"
177→	}
178→
179→	tags := input.Tags
180→	if tags == nil {
181→		tags = []string{}
182→	}
183→
184→	query := fmt.Sprintf(`INSERT INTO items (owner_id, type, status, sensitivity, title, content_text, tags, source, metadata, auto_metadata)
185→		VALUES ($1, 'text_note', 'ready', $2, $3, $4, $5, $6, '{}', '{}')
186→		RETURNING %s`, itemColumns)
187→
188→	row := s.pool.QueryRow(ctx, query,
189→		ownerID, input.Sensitivity, input.Title, input.Content, tags, input.Source)
190→
191→	it, err := scanItem(row)
192→	if err != nil {
193→		return nil, fmt.Errorf("item: capture note: %w", err)
194→	}
195→	return it, nil
196→}
197→
198→// Update partially updates an item. Only non-nil fields in input are changed.
199→func (s *Service) Update(ctx context.Context, ownerID, itemID uuid.UUID, input UpdateInput) (*Item, error) {
200→	sets := []string{}
201→	args := []any{ownerID, itemID}
202→	paramIdx := 3
203→
204→	if input.Title != nil {
205→		sets = append(sets, fmt.Sprintf("title = $%d", paramIdx))
206→		args = append(args, *input.Title)
207→		paramIdx++
208→	}
209→	if input.Tags != nil {
210→		sets = append(sets, fmt.Sprintf("tags = $%d", paramIdx))
211→		args = append(args, input.Tags)
212→		paramIdx++
213→	}
214→	if input.Sensitivity != nil {
215→		sets = append(sets, fmt.Sprintf("sensitivity = $%d", paramIdx))
216→		args = append(args, *input.Sensitivity)
217→		paramIdx++ //nolint:ineffassign // keeps pattern consistent for future fields
218→	}
219→
220→	if len(sets) == 0 {
221→		return s.GetByID(ctx, ownerID, itemID)
222→	}
223→
224→	query := fmt.Sprintf(`UPDATE items SET %s WHERE owner_id = $1 AND id = $2 RETURNING %s`,
225→		joinSets(sets), itemColumns)
226→
227→	row := s.pool.QueryRow(ctx, query, args...)
228→	it, err := scanItem(row)
229→	if errors.Is(err, pgx.ErrNoRows) {
230→		return nil, fmt.Errorf("item: update: not found")
231→	}
232→	if err != nil {
233→		return nil, fmt.Errorf("item: update: %w", err)
234→	}
235→	return it, nil
236→}
237→
238→// Delete removes an item by ID and owner. Returns an error if not found.
239→func (s *Service) Delete(ctx context.Context, ownerID, itemID uuid.UUID) error {
240→	tag, err := s.pool.Exec(ctx,
241→		"DELETE FROM items WHERE owner_id = $1 AND id = $2",
242→		ownerID, itemID)
243→	if err != nil {
244→		return fmt.Errorf("item: delete: %w", err)
245→	}
246→	if tag.RowsAffected() == 0 {
247→		return fmt.Errorf("item: delete: not found")
248→	}
249→	return nil
250→}
251→
252→// UpdateSensitivity changes an item's sensitivity level.
253→func (s *Service) UpdateSensitivity(ctx context.Context, ownerID, itemID uuid.UUID, sensitivity string) (*Item, error) {
254→	query := fmt.Sprintf(`UPDATE items SET sensitivity = $3 WHERE owner_id = $1 AND id = $2 RETURNING %s`, itemColumns)
255→	row := s.pool.QueryRow(ctx, query, ownerID, itemID, sensitivity)
256→	it, err := scanItem(row)
257→	if errors.Is(err, pgx.ErrNoRows) {
258→		return nil, fmt.Errorf("item: update sensitivity: not found")
259→	}
260→	if err != nil {
261→		return nil, fmt.Errorf("item: update sensitivity: %w", err)
262→	}
263→	return it, nil
264→}
265→
266→// Tag replaces an item's tags.
267→func (s *Service) Tag(ctx context.Context, ownerID, itemID uuid.UUID, tags []string) (*Item, error) {
268→	if tags == nil {
269→		tags = []string{}
270→	}
271→	query := fmt.Sprintf(`UPDATE items SET tags = $3 WHERE owner_id = $1 AND id = $2 RETURNING %s`, itemColumns)
272→	row := s.pool.QueryRow(ctx, query, ownerID, itemID, tags)
273→	it, err := scanItem(row)
274→	if errors.Is(err, pgx.ErrNoRows) {
275→		return nil, fmt.Errorf("item: tag: not found")
276→	}
277→	if err != nil {
278→		return nil, fmt.Errorf("item: tag: %w", err)
279→	}
280→	return it, nil
281→}
282→
283→func joinSets(sets []string) string {
284→	result := ""
285→	for i, s := range sets {
286→		if i > 0 {
287→			result += ", "
288→		}
289→		result += s
290→	}
291→	return result
292→}
