	it, err := r.ItemService.UpdateSensitivity(ctx, claims.UserID, itemID, sensitivityToString(&sensitivity))
	if err != nil {
		return nil, fmt.Errorf("resolver: update sensitivity: %w", err)
	}
	return toGraphQLItem(it), nil
}

// TagItem is the resolver for the tagItem field.
func (r *mutationResolver) TagItem(ctx context.Context, id string, tags []string) (*model.Item, error) {
	claims, err := requireAuth(ctx)
	if err != nil {
		return nil, err
	}

	itemID, err := uuid.Parse(id)
	if err != nil {
		return nil, fmt.Errorf("resolver: invalid item id: %w", err)
	}

	it, err := r.ItemService.Tag(ctx, claims.UserID, itemID, tags)
	if err != nil {
		return nil, fmt.Errorf("resolver: tag item: %w", err)
	}
	return toGraphQLItem(it), nil
}

// Item is the resolver for the item field.
func (r *queryResolver) Item(ctx context.Context, id string) (*model.Item, error) {
	claims, err := requireAuth(ctx)
	if err != nil {
		return nil, err
	}

	itemID, err := uuid.Parse(id)
	if err != nil {
		return nil, fmt.Errorf("resolver: invalid item id: %w", err)
	}

	it, err := r.ItemService.GetByID(ctx, claims.UserID, itemID)
	if err != nil {
		return nil, fmt.Errorf("resolver: item: %w", err)
	}
	if it == nil {
		return nil, nil
	}
	return toGraphQLItem(it), nil
}

// Items is the resolver for the items field.
func (r *queryResolver) Items(ctx context.Context, filter *model.ItemFilter, limit *int, offset *int, sort *model.ItemSort) (*model.SearchResult, error) {
	claims, err := requireAuth(ctx)
	if err != nil {
		return nil, err
	}

	result, err := r.ItemService.List(ctx, claims.UserID,
		toItemFilter(filter),
		derefIntOr(limit, 20),
		derefIntOr(offset, 0),
		toItemSort(sort))
	if err != nil {
		return nil, fmt.Errorf("resolver: items: %w", err)
	}

	return &model.SearchResult{
		Items:   toGraphQLItems(result.Items),
		Total:   result.Total,
		HasMore: result.HasMore,
	}, nil
}

// Search is the resolver for the search field.
func (r *queryResolver) Search(ctx context.Context, query string, filter *model.ItemFilter, limit *int, threshold *float64) (*model.SearchResult, error) {
	claims, err := requireAuth(ctx)
	if err != nil {
		return nil, err
	}

	result, err := r.ItemService.Search(ctx, claims.UserID, query,
		toItemFilter(filter),
		derefIntOr(limit, 20),
		derefFloat64Or(threshold, 0.0))
	if err != nil {
		return nil, fmt.Errorf("resolver: search: %w", err)
	}

	return &model.SearchResult{
		Items:   toGraphQLItems(result.Items),
		Total:   result.Total,
		HasMore: result.HasMore,
	}, nil
}

// Mutation returns generated.MutationResolver implementation.
func (r *Resolver) Mutation() generated.MutationResolver { return &mutationResolver{r} }

// Query returns generated.QueryResolver implementation.
func (r *Resolver) Query() generated.QueryResolver { return &queryResolver{r} }

type mutationResolver struct{ *Resolver }
type queryResolver struct{ *Resolver }

package main

import (
	"context"
	"flag"
	"log/slog"
	"os"
	"os/exec"
	"os/signal"
	"syscall"

	"github.com/joho/godotenv"
	"github.com/riverqueue/river"
	"github.com/riverqueue/river/riverdriver/riverpgxv5"

	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/config"
	"github.com/ketang/flotsam/api/internal/db"
	"github.com/ketang/flotsam/api/internal/item"
	"github.com/ketang/flotsam/api/internal/router"
	"github.com/ketang/flotsam/api/internal/server"
	"github.com/ketang/flotsam/api/internal/storage"
	"github.com/ketang/flotsam/api/internal/version"
)

func main() {
	withWorker := flag.Bool("with-worker", false, "fork flotsam-worker --watch as a child process")
	flag.Parse()

	// 1. Load .env (no-op if file is absent — dev convenience only)
	_ = godotenv.Load()

	// 2. Parse and validate configuration
	cfg, err := config.Load()
	if err != nil {
		slog.Error("failed to load config", "error", err)
		os.Exit(1)
	}

	// 3. Configure structured logger
	slog.SetDefault(slog.New(cfg.LogHandler()))
	slog.Info("starting flotsam api",
		"version", version.Version,
		"build_time", version.BuildTime,
		"env", cfg.Env,
	)

	// 4. Connect to database
	ctx := context.Background()
	pool, err := db.Connect(ctx, cfg.DatabaseURL)
	if err != nil {
		slog.Error("failed to connect to database", "error", err)
		os.Exit(1) //nolint:gocritic // fatal startup error
	}
	defer pool.Close()

	// 5. Initialize S3 storage client (optional)
	var store *storage.Client
	if cfg.S3Endpoint != "" {
		store, err = storage.New(storage.Config{
			Endpoint:       cfg.S3Endpoint,
			Bucket:         cfg.S3Bucket,
			AccessKey:      cfg.S3AccessKey,
			SecretKey:      cfg.S3SecretKey,
			Region:         cfg.S3Region,
			ForcePathStyle: cfg.S3ForcePathStyle,
		})
		if err != nil {
			slog.Error("failed to initialize storage", "error", err)
			os.Exit(1) //nolint:gocritic // fatal startup error
		}
		slog.Info("storage: S3 client initialized", "endpoint", cfg.S3Endpoint, "bucket", cfg.S3Bucket)
	} else {
		slog.Warn("storage: S3_ENDPOINT not set, object storage disabled")
	}

	// 6. Initialize River client (insert-only — no workers, no queues)
	riverClient, err := river.NewClient(riverpgxv5.New(pool), &river.Config{})
	if err != nil {
		slog.Error("failed to create river client", "error", err)
		os.Exit(1)
	}
	slog.Info("river: insert-only client initialized")

	// 7. Initialize auth validator
	validator := auth.NewHMACValidator(cfg.JWTSecret)
	slog.Info("auth: using HS256 JWT validator")

	// 8. Initialize services
	itemService := item.New(pool)

	// 9. Build router
	r := router.New(router.Deps{
		Config:      cfg,
		Pool:        pool,
		Validator:   validator,
		Storage:     store,
		RiverClient: riverClient,
		Items:       itemService,
	})

	// 9. Optionally fork worker as child process
	var workerCmd *exec.Cmd
	if *withWorker {
		workerCmd = exec.Command("flotsam-worker", "--watch")
		workerCmd.Stdout = os.Stdout
		workerCmd.Stderr = os.Stderr
		if err := workerCmd.Start(); err != nil {
			slog.Error("failed to start worker", "error", err)
		} else {
			slog.Info("worker: started as child process", "pid", workerCmd.Process.Pid)
		}
	}

	// 10. Start HTTP server
	srv := server.New(cfg.Addr(), r)

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		slog.Info("server: listening", "addr", cfg.Addr())
		if err := srv.Start(); err != nil {
			slog.Info("server: stopped", "reason", err)
		}
	}()

	// 11. Block until signal received
	sig := <-sigCh
	slog.Info("signal received", "signal", sig)

	// 12. Graceful shutdown
	shutdownCtx, cancel := context.WithTimeout(context.Background(), cfg.ShutdownTimeout)
	defer cancel()

	slog.Info("server: shutting down", "timeout", cfg.ShutdownTimeout)
	if err := srv.Shutdown(shutdownCtx); err != nil {
		slog.Error("server: shutdown error", "error", err)
		os.Exit(1)
	}

	// Kill worker child process if running
	if workerCmd != nil && workerCmd.Process != nil {
		slog.Info("worker: stopping child process", "pid", workerCmd.Process.Pid)
		_ = workerCmd.Process.Signal(syscall.SIGTERM)
		_ = workerCmd.Wait()
	}

	slog.Info("server: shutdown complete")
}

package config

import (
	"fmt"
	"log/slog"
	"os"
	"time"

	"github.com/caarlos0/env/v11"
)

// Config holds all application configuration loaded from environment variables.
type Config struct {
	Host string `env:"HOST" envDefault:"0.0.0.0"`
	Port int    `env:"PORT" envDefault:"8081"`

	DatabaseURL string `env:"DATABASE_URL,required"`
	JWTSecret   string `env:"JWT_SECRET,required"` //nolint:gosec // config field name, not a hardcoded secret

	S3Endpoint       string `env:"S3_ENDPOINT"`
	S3Bucket         string `env:"S3_BUCKET" envDefault:"flotsam-dev"`
	S3AccessKey      string `env:"S3_ACCESS_KEY"`
	S3SecretKey      string `env:"S3_SECRET_KEY"`
	S3Region         string `env:"S3_REGION" envDefault:"us-east-1"`
	S3ForcePathStyle bool   `env:"S3_FORCE_PATH_STYLE" envDefault:"false"`

	OpenAIAPIKey string `env:"OPENAI_API_KEY"`
	OllamaURL    string `env:"OLLAMA_URL"`

	LogLevel  string `env:"LOG_LEVEL" envDefault:"info"`
	LogFormat string `env:"LOG_FORMAT" envDefault:"json"`

	Env string `env:"ENV" envDefault:"development"`

	CORSOrigins string `env:"CORS_ORIGINS"`

	GQLPlayground    bool `env:"GRAPHQL_PLAYGROUND" envDefault:"false"`
	GQLIntrospection bool `env:"GRAPHQL_INTROSPECTION" envDefault:"false"`

	MCPEnabled bool `env:"MCP_ENABLED" envDefault:"true"`

	RateLimitEnabled     bool `env:"RATE_LIMIT_ENABLED" envDefault:"true"`
	RateLimitGraphQL     int  `env:"RATE_LIMIT_GRAPHQL" envDefault:"60"`
	RateLimitGraphQLAuth int  `env:"RATE_LIMIT_GRAPHQL_AUTH" envDefault:"120"`
	RateLimitMCP         int  `env:"RATE_LIMIT_MCP" envDefault:"120"`

	ShutdownTimeout time.Duration `env:"SHUTDOWN_TIMEOUT" envDefault:"15s"`
}

// Load parses and validates configuration from environment variables.
func Load() (*Config, error) {
	cfg := &Config{}
	if err := env.Parse(cfg); err != nil {
		return nil, fmt.Errorf("config: %w", err)
	}
	return cfg, nil
}

// Addr returns the host:port bind address.
func (c *Config) Addr() string {
	return fmt.Sprintf("%s:%d", c.Host, c.Port)
}

// ParseLogLevel converts a log level string to the corresponding slog.Level.
func ParseLogLevel(s string) slog.Level {
	switch s {
	case "trace":
		return slog.Level(-8) // custom TRACE level
	case "debug":
		return slog.LevelDebug
	case "warn":
		return slog.LevelWarn
	case "error":
		return slog.LevelError
	default:
		return slog.LevelInfo
	}
}

// LogHandler returns an slog.Handler configured per LOG_LEVEL and LOG_FORMAT.
func (c *Config) LogHandler() slog.Handler {
	level := ParseLogLevel(c.LogLevel)
	opts := &slog.HandlerOptions{
		Level:     level,
		AddSource: c.Env == "development",
	}

	if c.LogFormat == "text" {
		return slog.NewTextHandler(os.Stderr, opts)
	}
	return slog.NewJSONHandler(os.Stderr, opts)
}

