package resolver

import (
	"context"
	"errors"
	"strings"

	"github.com/ketang/flotsam/api/graph/model"
	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/item"
)

var errAuthRequired = errors.New("resolver: authentication required")

// requireAuth extracts auth claims from context or returns an error.
func requireAuth(ctx context.Context) (*auth.Claims, error) {
	claims := auth.GetClaims(ctx)
	if claims == nil {
		return nil, errAuthRequired
	}
	return claims, nil
}

// toGraphQLItem maps a domain Item to the GraphQL model Item.
func toGraphQLItem(it *item.Item) *model.Item {
	return &model.Item{
		ID:           it.ID.String(),
		Type:         model.ItemType(strings.ToUpper(it.Type)),
		Status:       model.ItemStatus(strings.ToUpper(it.Status)),
		Sensitivity:  model.SensitivityLevel(strings.ToUpper(it.Sensitivity)),
		Title:        it.Title,
		ContentText:  it.ContentText,
		ContentURL:   it.ContentURL,
		Tags:         ensureStringSlice(it.Tags),
		Metadata:     ensureMap(it.Metadata),
		AutoMetadata: ensureMap(it.AutoMetadata),
		Source:       it.Source,
		SourceURL:    it.SourceURL,
		CreatedAt:    it.CreatedAt,
		UpdatedAt:    it.UpdatedAt,
		CapturedAt:   it.CapturedAt,
	}
}

// toGraphQLItems maps a slice of domain Items to GraphQL model Items.
func toGraphQLItems(items []*item.Item) []*model.Item {
	result := make([]*model.Item, len(items))
	for i, it := range items {
		result[i] = toGraphQLItem(it)
	}
	return result
}

// toItemFilter converts a GraphQL ItemFilter to a domain Filter.
func toItemFilter(f *model.ItemFilter) *item.Filter {
	if f == nil {
		return nil
	}
	result := &item.Filter{
		Source: f.Source,
	}
	for _, t := range f.Types {
		result.Types = append(result.Types, strings.ToLower(string(t)))
	}
	for _, s := range f.Status {
		result.Status = append(result.Status, strings.ToLower(string(s)))
	}
	for _, s := range f.Sensitivity {
		result.Sensitivity = append(result.Sensitivity, strings.ToLower(string(s)))
	}
	result.Tags = f.Tags
	if f.DateFrom != nil {
		result.DateFrom = f.DateFrom
	}
	if f.DateTo != nil {
		result.DateTo = f.DateTo
	}
	return result
}

// toItemSort converts a GraphQL ItemSort to a domain Sort.
func toItemSort(s *model.ItemSort) *item.Sort {
	if s == nil {
		return nil
	}
	return &item.Sort{
		Field:     string(s.Field),
		Direction: string(s.Direction),
	}
}

// sensitivityToString converts a GraphQL SensitivityLevel to lowercase DB string.
// Returns "normal" if nil.
func sensitivityToString(s *model.SensitivityLevel) string {
	if s == nil {
		return "normal"
	}
	return strings.ToLower(string(*s))
}

func ensureStringSlice(s []string) []string {
	if s == nil {
		return []string{}
	}
	return s
}

func ensureMap(m map[string]any) map[string]any {
	if m == nil {
		return map[string]any{}
	}
	return m
}

func derefIntOr(p *int, def int) int {
	if p == nil {
		return def
	}
	return *p
}

func derefFloat64Or(p *float64, def float64) float64 {
	if p == nil {
		return def
	}
	return *p
}

