package auth

import (
	"fmt"

	"golang.org/x/crypto/bcrypt"
)

// HashPassword returns a bcrypt hash of the given password.
func HashPassword(password string) (string, error) {
	hash, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
	if err != nil {
		return "", fmt.Errorf("auth: hash password: %w", err)
	}
	return string(hash), nil
}

// CheckPassword compares a bcrypt hash with a plaintext password.
// Returns nil on success or an error if they don't match.
func CheckPassword(hash, password string) error {
	if err := bcrypt.CompareHashAndPassword([]byte(hash), []byte(password)); err != nil {
		return fmt.Errorf("auth: check password: %w", err)
	}
	return nil
}

package auth

import (
	"testing"

	"golang.org/x/crypto/bcrypt"
)

func TestHashPassword(t *testing.T) {
	hash, err := HashPassword("my-secret-password")
	if err != nil {
		t.Fatalf("HashPassword() error = %v", err)
	}
	if hash == "" {
		t.Fatal("HashPassword() returned empty string")
	}
	// Verify it's valid bcrypt
	if err := bcrypt.CompareHashAndPassword([]byte(hash), []byte("my-secret-password")); err != nil {
		t.Errorf("produced hash is not valid bcrypt: %v", err)
	}
}

func TestHashPassword_DifferentHashes(t *testing.T) {
	h1, _ := HashPassword("password")
	h2, _ := HashPassword("password")
	if h1 == h2 {
		t.Error("same password should produce different hashes (different salts)")
	}
}

func TestCheckPassword_Correct(t *testing.T) {
	hash, _ := HashPassword("correct-password")
	if err := CheckPassword(hash, "correct-password"); err != nil {
		t.Errorf("CheckPassword() with correct password: %v", err)
	}
}

func TestCheckPassword_Wrong(t *testing.T) {
	hash, _ := HashPassword("correct-password")
	if err := CheckPassword(hash, "wrong-password"); err == nil {
		t.Error("CheckPassword() with wrong password should return error")
	}
}

func TestCheckPassword_InvalidHash(t *testing.T) {
	if err := CheckPassword("not-a-bcrypt-hash", "password"); err == nil {
		t.Error("CheckPassword() with invalid hash should return error")
	}
}

package auth

import (
	"fmt"
	"time"

	"github.com/golang-jwt/jwt/v5"
	"github.com/google/uuid"
)

// Issuer creates signed JWT tokens.
type Issuer struct {
	secret   []byte
	duration time.Duration
}

// NewIssuer creates a new token issuer with the given HMAC secret and token duration.
func NewIssuer(secret string, duration time.Duration) *Issuer {
	return &Issuer{
		secret:   []byte(secret),
		duration: duration,
	}
}

// Issue creates and signs a new JWT for the given user.
func (iss *Issuer) Issue(userID uuid.UUID, email, clientType string) (string, error) {
	now := time.Now()
	claims := &Claims{
		UserID:     userID,
		Email:      email,
		ClientType: clientType,
		RegisteredClaims: jwt.RegisteredClaims{
			Subject:   userID.String(),
			IssuedAt:  jwt.NewNumericDate(now),
			ExpiresAt: jwt.NewNumericDate(now.Add(iss.duration)),
		},
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	signed, err := token.SignedString(iss.secret)
	if err != nil {
		return "", fmt.Errorf("auth: issue token: %w", err)
	}
	return signed, nil
}

package auth

import (
	"testing"
	"time"

	"github.com/google/uuid"
)

func TestIssue_RoundTrip(t *testing.T) {
	secret := "test-secret-key"
	issuer := NewIssuer(secret, 1*time.Hour)
	validator := NewHMACValidator(secret)

	userID := uuid.New()
	email := "test@example.com"

	token, err := issuer.Issue(userID, email, "web")
	if err != nil {
		t.Fatalf("Issue() error = %v", err)
	}
	if token == "" {
		t.Fatal("Issue() returned empty token")
	}

	claims, err := validator.Validate(token)
	if err != nil {
		t.Fatalf("Validate() error = %v", err)
	}

	if claims.UserID != userID {
		t.Errorf("UserID = %v, want %v", claims.UserID, userID)
	}
	if claims.Email != email {
		t.Errorf("Email = %q, want %q", claims.Email, email)
	}
	if claims.ClientType != "web" {
		t.Errorf("ClientType = %q, want %q", claims.ClientType, "web")
	}
}

func TestIssue_Expiry(t *testing.T) {
	issuer := NewIssuer("secret", 2*time.Hour)
	validator := NewHMACValidator("secret")

	token, err := issuer.Issue(uuid.New(), "user@test.com", "cli")
	if err != nil {
		t.Fatalf("Issue() error = %v", err)
	}

	claims, err := validator.Validate(token)
