// Register is the resolver for the register field.
func (r *mutationResolver) Register(ctx context.Context, input model.RegisterInput) (*model.AuthPayload, error) {
	displayName := ""
	if input.DisplayName != nil {
		displayName = *input.DisplayName
	}

	u, err := r.UserService.Create(ctx, input.Email, input.Password, displayName)
	if err != nil {
		if err == user.ErrEmailTaken {
			return nil, fmt.Errorf("resolver: register: email already in use")
		}
		return nil, fmt.Errorf("resolver: register: %w", err)
	}

	token, err := r.Issuer.Issue(u.ID, u.Email, "web")
	if err != nil {
		return nil, fmt.Errorf("resolver: register: %w", err)
	}

	return &model.AuthPayload{
		Token: token,
		User:  toGraphQLUser(u),
	}, nil
}

// Login is the resolver for the login field.
func (r *mutationResolver) Login(ctx context.Context, input model.LoginInput) (*model.AuthPayload, error) {
	u, err := r.UserService.GetByEmail(ctx, input.Email)
	if err != nil {
		return nil, fmt.Errorf("resolver: login: %w", err)
	}
	if u == nil {
		return nil, fmt.Errorf("resolver: login: invalid credentials")
	}

	if u.PasswordHash == nil {
		return nil, fmt.Errorf("resolver: login: invalid credentials")
	}

	if err := auth.CheckPassword(*u.PasswordHash, input.Password); err != nil {
		return nil, fmt.Errorf("resolver: login: invalid credentials")
	}

	token, err := r.Issuer.Issue(u.ID, u.Email, "web")
	if err != nil {
		return nil, fmt.Errorf("resolver: login: %w", err)
	}

	return &model.AuthPayload{
		Token: token,
		User:  toGraphQLUser(u),
	}, nil
}

// Me is the resolver for the me field.
func (r *queryResolver) Me(ctx context.Context) (*model.User, error) {
	claims := auth.GetClaims(ctx)
	if claims == nil {
		return nil, nil
	}

	u, err := r.UserService.GetByID(ctx, claims.UserID)
	if err != nil {
		return nil, fmt.Errorf("resolver: me: %w", err)
	}
	if u == nil {
		return nil, nil
	}
	return toGraphQLUser(u), nil
}

